import {
  createUserWithEmailAndPassword,
  signInWithEmailAndPassword,
  signOut,
  onAuthStateChanged,
  User,
} from 'firebase/auth';
import { doc, setDoc, getDoc, collection, query, where, getDocs, updateDoc } from 'firebase/firestore';
import { auth, db } from './firebase';
import { uploadImageToImgBB } from './imgbb';

export const registerUser = async (
  email: string,
  password: string,
  username: string,
  userId: string
) => {
  try {
    // Проверяем что userId не занят
    const usersRef = collection(db, 'users');
    const q = query(usersRef, where('userId', '==', userId));
    const querySnapshot = await getDocs(q);

    if (!querySnapshot.empty) {
      throw new Error('Этот ID уже занят');
    }

    // Регистрируем пользователя
    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    const user = userCredential.user;

    // Создаём профиль пользователя
    await setDoc(doc(db, 'users', user.uid), {
      userId,
      username,
      email,
      avatar_url: null,
      created_at: new Date().toISOString(),
    });

    return user;
  } catch (error: any) {
    let message = 'Ошибка регистрации';

    if (error.code === 'auth/email-already-in-use') {
      message = 'Этот email уже зарегистрирован';
    } else if (error.code === 'auth/weak-password') {
      message = 'Пароль слишком слабый (минимум 6 символов)';
    } else if (error.code === 'auth/invalid-email') {
      message = 'Неверный формат email';
    } else if (error.message === 'Этот ID уже занят') {
      message = 'Этот ID уже занят';
    } else {
      message = error.message;
    }

    throw new Error(message);
  }
};

export const loginUser = async (email: string, password: string) => {
  try {
    const userCredential = await signInWithEmailAndPassword(auth, email, password);
    return userCredential.user;
  } catch (error: any) {
    let message = 'Ошибка входа';

    if (error.code === 'auth/invalid-credential') {
      message = 'Неверный email или пароль';
    } else if (error.code === 'auth/too-many-requests') {
      message = 'Слишком много попыток входа. Попробуйте позже';
    } else {
      message = error.message;
    }

    throw new Error(message);
  }
};

export const logoutUser = async () => {
  try {
    await signOut(auth);
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const getCurrentUser = async () => {
  try {
    return auth.currentUser;
  } catch (error: any) {
    return null;
  }
};

export const getUserProfile = async (userId: string) => {
  try {
    const userDoc = await getDoc(doc(db, 'users', userId));
    return userDoc.exists() ? userDoc.data() : null;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const getUserUsername = async (userId: string): Promise<string> => {
  try {
    const profile = await getUserProfile(userId);
    return profile?.username || 'Unknown';
  } catch (error: any) {
    return 'Unknown';
  }
};

export const updateUserProfile = async (
  userId: string,
  username: string,
  userIdDisplay?: string,
  avatarUrl?: string,
  isHidden?: boolean
) => {
  try {
    const currentUser = auth.currentUser;
    if (!currentUser || currentUser.uid !== userId) {
      throw new Error('Unauthorized');
    }

    const updateData: any = { username };
    if (avatarUrl) {
      updateData.avatar_url = avatarUrl;
    }

    await updateDoc(doc(db, 'users', userId), updateData);
  } catch (error: any) {
    throw new Error(error.message || 'Ошибка обновления профиля');
  }
};

export const uploadAvatar = async (userId: string, file: File) => {
  try {
    const avatarUrl = await uploadImageToImgBB(file);

    const currentUser = auth.currentUser;
    if (!currentUser || currentUser.uid !== userId) {
      throw new Error('Unauthorized');
    }

    await updateDoc(doc(db, 'users', userId), {
      avatar_url: avatarUrl,
    });

    return avatarUrl;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const blockUser = async (userId: string, blockedUserId: string) => {
  try {
    await setDoc(doc(db, 'blocked_users', `${userId}_${blockedUserId}`), {
      user_id: userId,
      blocked_user_id: blockedUserId,
      created_at: new Date().toISOString(),
    });
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const unblockUser = async (userId: string, blockedUserId: string) => {
  try {
    const blockedRef = collection(db, 'blocked_users');
    const q = query(blockedRef, where('user_id', '==', userId), where('blocked_user_id', '==', blockedUserId));
    const querySnapshot = await getDocs(q);

    querySnapshot.forEach(async (docSnapshot) => {
      await updateDoc(doc(db, 'blocked_users', docSnapshot.id), { deleted: true });
    });
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const getBlockedUsers = async (userId: string) => {
  try {
    const blockedRef = collection(db, 'blocked_users');
    const q = query(blockedRef, where('user_id', '==', userId), where('deleted', '!=', true));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map((doc) => doc.data().blocked_user_id) || [];
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const isUserBlocked = async (userId: string, otherUserId: string) => {
  try {
    const blockedRef = collection(db, 'blocked_users');
    const q = query(
      blockedRef,
      where('user_id', '==', userId),
      where('blocked_user_id', '==', otherUserId),
      where('deleted', '!=', true)
    );
    const querySnapshot = await getDocs(q);
    return !querySnapshot.empty;
  } catch (error: any) {
    return false;
  }
};
